import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"电力新能源赛道总览","description":"","frontmatter":{},"headers":[],"relativePath":"电力新能源/赛道总览.md","filePath":"电力新能源/赛道总览.md","lastUpdated":1781602495000}'),o={name:"电力新能源/赛道总览.md"};function h(n,t,s,l,i,g){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="电力新能源赛道总览" tabindex="-1">电力新能源赛道总览 <a class="header-anchor" href="#电力新能源赛道总览" aria-label="Permalink to &quot;电力新能源赛道总览&quot;">​</a></h1><p><strong>更新：</strong> 2026-06-15 ⚡ 已接入实时数据 | <strong>视角：</strong> PE/VC 一级股权投资 <strong>数据源：</strong> China Energy MCP（国家能源局/中电联）、Prospector Energy MCP（美国并网队列）</p><hr><h2 id="一、宏观背景" tabindex="-1">一、宏观背景 <a class="header-anchor" href="#一、宏观背景" aria-label="Permalink to &quot;一、宏观背景&quot;">​</a></h2><h3 id="双碳目标时间线" tabindex="-1">双碳目标时间线 <a class="header-anchor" href="#双碳目标时间线" aria-label="Permalink to &quot;双碳目标时间线&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间节点</th><th>目标</th></tr></thead><tbody><tr><td>2025</td><td>非化石能源消费占比 20% ✓</td></tr><tr><td>2030</td><td>碳达峰，非化石能源占比 25%，风光总装机 12亿千瓦+</td></tr><tr><td>2035</td><td>新型电力系统基本建成</td></tr><tr><td>2060</td><td>碳中和</td></tr></tbody></table><h3 id="十五五规划重点-2026-2030" tabindex="-1">十五五规划重点（2026-2030） <a class="header-anchor" href="#十五五规划重点-2026-2030" aria-label="Permalink to &quot;十五五规划重点（2026-2030）&quot;">​</a></h3><ul><li>新型电力系统：源网荷储一体化、柔性互联</li><li>新能源装机：风光年增 2亿千瓦+（已超额完成十五计划）</li><li>电力市场化改革：现货市场全覆盖、容量电价全面推行</li><li>氢能：纳入国家能源管理体系</li><li>碳市场：扩围至钢铁/水泥/电解铝</li></ul><h3 id="当前市场格局-2025-2026-—-实时数据" tabindex="-1">当前市场格局（2025-2026）— 实时数据 <a class="header-anchor" href="#当前市场格局-2025-2026-—-实时数据" aria-label="Permalink to &quot;当前市场格局（2025-2026）— 实时数据&quot;">​</a></h3><h4 id="🇨🇳-中国市场-国家能源局-中电联" tabindex="-1">🇨🇳 中国市场（国家能源局/中电联） <a class="header-anchor" href="#🇨🇳-中国市场-国家能源局-中电联" aria-label="Permalink to &quot;🇨🇳 中国市场（国家能源局/中电联）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>指标</th><th>数据</th><th>同比/备注</th></tr></thead><tbody><tr><td>风电累计装机</td><td><strong>5.2亿千瓦</strong></td><td>年新增约8000万千瓦</td></tr><tr><td>光伏累计装机</td><td><strong>8.9亿千瓦</strong></td><td>年新增约2.5亿千瓦</td></tr><tr><td>风光合计</td><td><strong>14.1亿千瓦</strong></td><td>提前超额完成2030年12亿千瓦目标</td></tr><tr><td>新型储能累计装机</td><td><strong>7800万千瓦</strong></td><td>同比大幅增长</td></tr><tr><td>风电年发电量</td><td>10,531亿千瓦时</td><td>占比持续提升</td></tr><tr><td>光伏年发电量</td><td>5,726亿千瓦时</td><td>占比持续提升</td></tr><tr><td>可再生能源发电量占比</td><td><strong>35.2%</strong></td><td>加速提升</td></tr><tr><td>风电利用率</td><td>96.0%</td><td>维持在95%+健康水平</td></tr><tr><td>光伏利用率</td><td>97.5%</td><td>维持在95%+健康水平</td></tr><tr><td>数据中心用电量</td><td>1,933亿千瓦时</td><td>占全社会1.9%，增速17%</td></tr></tbody></table><p><strong>各省TOP5（按风光总装机）：</strong></p><table tabindex="0"><thead><tr><th>排名</th><th>省份</th><th>风电</th><th>光伏</th><th>总装机</th><th>特点</th></tr></thead><tbody><tr><td>1</td><td>内蒙古</td><td>8,200万kW</td><td>6,800万kW</td><td><strong>15,000万kW</strong></td><td>风资源最优，蒙西电价市场化</td></tr><tr><td>2</td><td>河北</td><td>3,800万kW</td><td>5,800万kW</td><td><strong>9,600万kW</strong></td><td>靠近负荷中心</td></tr><tr><td>3</td><td>山东</td><td>2,800万kW</td><td>6,500万kW</td><td><strong>9,300万kW</strong></td><td>光伏大省，现货正式运行</td></tr><tr><td>4</td><td>新疆</td><td>4,500万kW</td><td>5,200万kW</td><td><strong>9,700万kW</strong></td><td>光资源丰富</td></tr><tr><td>5</td><td>山西</td><td>2,800万kW</td><td>4,200万kW</td><td><strong>7,000万kW</strong></td><td>煤电调峰资源丰富</td></tr></tbody></table><p><strong>现货市场电价参考（2026年4月均价）：</strong></p><table tabindex="0"><thead><tr><th>省份</th><th>均价(元/MWh)</th><th>市场状态</th><th>特点</th></tr></thead><tbody><tr><td>广东</td><td>637.91</td><td>正式运行</td><td>高位运行，负荷中心溢价</td></tr><tr><td>山东</td><td>280</td><td>正式运行</td><td>回落趋势</td></tr><tr><td>山西</td><td>230</td><td>正式运行</td><td>时段性供需错配</td></tr><tr><td>甘肃</td><td>145.12</td><td>正式运行</td><td>新能源大发，午间地板价</td></tr><tr><td>辽宁</td><td>127.03</td><td>连续结算试运行</td><td>大幅回落</td></tr></tbody></table><blockquote><p>⚠ 现货电价随供需实时波动，上述为月度均价。甘肃/辽宁低价区意味着储能套利空间大。</p></blockquote><h4 id="🇺🇸-美国市场-prospector-energy-并网队列数据" tabindex="-1">🇺🇸 美国市场（Prospector Energy 并网队列数据） <a class="header-anchor" href="#🇺🇸-美国市场-prospector-energy-并网队列数据" aria-label="Permalink to &quot;🇺🇸 美国市场（Prospector Energy 并网队列数据）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>指标</th><th>数据</th></tr></thead><tbody><tr><td>在册项目总数</td><td><strong>47,812个</strong></td></tr><tr><td>总容量</td><td><strong>6,767.6 GW</strong></td></tr><tr><td>ITC合格项目数</td><td>36,363个</td></tr><tr><td>能源社区红利项目</td><td>18,181个</td></tr><tr><td>ITC总估值</td><td>$3.34万亿</td></tr></tbody></table><p><strong>按技术类型（在册项目）：</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>项目数</th><th>总容量</th></tr></thead><tbody><tr><td>Solar</td><td>17,252</td><td>1,384.6 GW</td></tr><tr><td>Storage</td><td>7,344</td><td>918.9 GW</td></tr><tr><td>Wind</td><td>6,526</td><td>1,245.9 GW</td></tr><tr><td>Gas</td><td>4,222</td><td>1,248.9 GW</td></tr><tr><td>Solar+Storage</td><td>4,137</td><td>704.8 GW</td></tr><tr><td>Offshore Wind</td><td>121</td><td>47.4 GW</td></tr><tr><td>Nuclear</td><td>192</td><td>71.0 GW</td></tr></tbody></table><p><strong>按ISO/RTO分布（TOP5）：</strong></p><table tabindex="0"><thead><tr><th>ISO</th><th>项目数</th><th>容量</th></tr></thead><tbody><tr><td>CAISO</td><td>10,388</td><td>849.6 GW</td></tr><tr><td>PJM</td><td>10,262</td><td>732.1 GW</td></tr><tr><td>West (非ISO)</td><td>6,628</td><td>1,245.8 GW</td></tr><tr><td>MISO</td><td>5,553</td><td>1,033.1 GW</td></tr><tr><td>ERCOT</td><td>3,907</td><td>827.0 GW</td></tr></tbody></table><blockquote><p>🔗 数据来源：<code>china-energy_get_national_stats</code>, <code>china-energy_get_province_stats</code>, <code>china-energy_get_spot_prices</code>, <code>prospector-energy_get_queue_stats</code> 数据获取日期：2026-06-15</p></blockquote><h4 id="一级市场投资信号提炼" tabindex="-1">一级市场投资信号提炼 <a class="header-anchor" href="#一级市场投资信号提炼" aria-label="Permalink to &quot;一级市场投资信号提炼&quot;">​</a></h4><table tabindex="0"><thead><tr><th>信号</th><th>解读</th></tr></thead><tbody><tr><td>中国风光装机已超14亿kW</td><td>增量市场转向存量运营，运维/数字化/交易机会增加</td></tr><tr><td>储能7800万kW</td><td>配储从政策驱动转向经济性驱动，独立储能商业模式跑通</td></tr><tr><td>广东现货电价637 vs 甘肃145</td><td>区域价差拉大，储能跨区套利+电力交易AI价值凸显</td></tr><tr><td>美国队列6.7TW</td><td>在册项目比实际装机大数倍，并网瓶颈是确定性机会</td></tr><tr><td>IRA ITC最高50%抵免</td><td>美国清洁能源投资吸引力上升，中资出海需关注本土化要求</td></tr></tbody></table><ul><li>电力市场化改革进入深水区，现货市场试点扩至全国</li><li>供给侧产能过剩（光伏组件/锂电），价格战加剧，行业洗牌</li><li>技术驱动型创新仍是 PE/VC 核心机会</li></ul><hr><h2 id="二、各子赛道概览" tabindex="-1">二、各子赛道概览 <a class="header-anchor" href="#二、各子赛道概览" aria-label="Permalink to &quot;二、各子赛道概览&quot;">​</a></h2><h3 id="_1-光伏-新技术方向" tabindex="-1">1. 光伏（新技术方向） <a class="header-anchor" href="#_1-光伏-新技术方向" aria-label="Permalink to &quot;1. 光伏（新技术方向）&quot;">​</a></h3><p><strong>成熟度：</strong> 主产业链成熟，新技术早期 <strong>PE/VC 机会：</strong> Perovskite 叠层、BIPV、光伏回收、光伏+数字化 <strong>当前周期：</strong> 产能过剩出清期，制造业利润承压，技术创新溢价</p><h3 id="_2-储能" tabindex="-1">2. 储能 <a class="header-anchor" href="#_2-储能" aria-label="Permalink to &quot;2. 储能&quot;">​</a></h3><p><strong>成熟度：</strong> 高速成长期 <strong>PE/VC 机会：</strong> 钠离子电池、液流电池、工商业储能、长时储能 <strong>当前周期：</strong> 政策红利释放期，产能开始过剩，技术分化加剧</p><h3 id="_3-风电-新技术方向" tabindex="-1">3. 风电（新技术方向） <a class="header-anchor" href="#_3-风电-新技术方向" aria-label="Permalink to &quot;3. 风电（新技术方向）&quot;">​</a></h3><p><strong>成熟度：</strong> 主产业链成熟，深远海/浮式早期 <strong>PE/VC 机会：</strong> 浮式风电平台、智慧运维、风电叶片回收、风电数字化 <strong>当前周期：</strong> 陆上平价，海上降本关键期</p><h3 id="_4-氢能" tabindex="-1">4. 氢能 <a class="header-anchor" href="#_4-氢能" aria-label="Permalink to &quot;4. 氢能&quot;">​</a></h3><p><strong>成熟度：</strong> 早期成长期 <strong>PE/VC 机会：</strong> 绿氢制备（PEM/AEM电解槽）、氢储运技术、燃料电池核心部件 <strong>当前周期：</strong> 政策驱动转向经济性驱动，绿氢降本是关键拐点</p><h3 id="_5-智能电网-虚拟电厂" tabindex="-1">5. 智能电网/虚拟电厂 <a class="header-anchor" href="#_5-智能电网-虚拟电厂" aria-label="Permalink to &quot;5. 智能电网/虚拟电厂&quot;">​</a></h3><p><strong>成熟度：</strong> 成长期 <strong>PE/VC 机会：</strong> VPP 聚合平台、电力交易 AI、微电网、需求侧响应 <strong>当前周期：</strong> 电改深化利好，数字化+市场化双轮驱动</p><h3 id="_6-碳市场" tabindex="-1">6. 碳市场 <a class="header-anchor" href="#_6-碳市场" aria-label="Permalink to &quot;6. 碳市场&quot;">​</a></h3><p><strong>成熟度：</strong> 启动期 <strong>PE/VC 机会：</strong> 碳资产管理平台、碳监测 CEMS、碳金融、ESG 数据 <strong>当前周期：</strong> 全国碳市场扩围在即，CCER 重启后供给不足</p><hr><h2 id="三、关键投资逻辑" tabindex="-1">三、关键投资逻辑 <a class="header-anchor" href="#三、关键投资逻辑" aria-label="Permalink to &quot;三、关键投资逻辑&quot;">​</a></h2><h3 id="一级股权机会矩阵" tabindex="-1">一级股权机会矩阵 <a class="header-anchor" href="#一级股权机会矩阵" aria-label="Permalink to &quot;一级股权机会矩阵&quot;">​</a></h3><table tabindex="0"><thead><tr><th>投资主题</th><th>确定性</th><th>市场空间</th><th>进入时机</th></tr></thead><tbody><tr><td>储能（电化学储能系统）</td><td>★★★★☆</td><td>万亿级</td><td>窗口期中期</td></tr><tr><td>钠离子电池</td><td>★★★☆☆</td><td>千亿级</td><td>早期布局</td></tr><tr><td>液流电池（长时储能）</td><td>★★★★☆</td><td>百亿级</td><td>成长期</td></tr><tr><td>氢能（电解槽）</td><td>★★★☆☆</td><td>千亿级</td><td>风口期</td></tr><tr><td>钙钛矿光伏</td><td>★★★☆☆</td><td>千亿级</td><td>Pre-商业化</td></tr><tr><td>VPP 虚拟电厂</td><td>★★★★☆</td><td>百亿级</td><td>政策红利期</td></tr><tr><td>碳市场服务</td><td>★★★★☆</td><td>百亿级</td><td>启动期</td></tr></tbody></table><h3 id="核心关注信号" tabindex="-1">核心关注信号 <a class="header-anchor" href="#核心关注信号" aria-label="Permalink to &quot;核心关注信号&quot;">​</a></h3><ol><li><strong>产能出清进度</strong> — 制造业环节何时供需再平衡</li><li><strong>新型储能成本曲线</strong> — 钠电/液流何时平价</li><li><strong>绿氢 LCOH</strong> — 何时降至 20元/kg 以下</li><li><strong>电力现货市场进展</strong> — 哪些省份率先全面运行</li><li><strong>碳价走势</strong> — 从当前 70-100元/吨能否突破 200元</li></ol><hr><h2 id="四、风险因素" tabindex="-1">四、风险因素 <a class="header-anchor" href="#四、风险因素" aria-label="Permalink to &quot;四、风险因素&quot;">​</a></h2><table tabindex="0"><thead><tr><th>风险</th><th>影响</th></tr></thead><tbody><tr><td>产能过剩持续</td><td>制造业标的价值缩水，供应链利润挤出</td></tr><tr><td>政策节奏变动</td><td>补贴退坡速度、碳市场扩围时间不确定</td></tr><tr><td>技术路线替代</td><td>锂电→钠电→固态，钙钛矿→晶硅</td></tr><tr><td>地缘政治</td><td>光伏出海壁垒、风电出海认证、技术封锁</td></tr><tr><td>估值泡沫</td><td>部分赛道（储能/AI+能源）过热</td></tr></tbody></table><hr><h2 id="五、交叉链接" tabindex="-1">五、交叉链接 <a class="header-anchor" href="#五、交叉链接" aria-label="Permalink to &quot;五、交叉链接&quot;">​</a></h2><table tabindex="0"><thead><tr><th>关联赛道</th><th>链接</th><th>说明</th></tr></thead><tbody><tr><td><strong>算电协同</strong></td><td><a href="./../算电协同/赛道总览">赛道总览</a></td><td>电力新能源×AI 交叉核心赛道</td></tr><tr><td><strong>估值基准</strong></td><td><a href="./../一级市场估值基准">一级市场估值基准</a></td><td>PE/VC 各赛道估值参考区间</td></tr><tr><td><strong>当前关注</strong></td><td><a href="./../当前关注">当前关注</a></td><td>重点赛道优先级标记</td></tr></tbody></table>',52)])])}const u=d(o,[["render",h]]);export{c as __pageData,u as default};
